+/**
+ * Draw a warm radial gradient torch glow with flicker.
+ * @param ctx CanvasRenderingContext2D
+ * @param x center x
+ * @param y center y
+ * @param baseRadius base radius of glow
+ * @param intensity glow intensity (0 to 1)
+ * @param frame current frame for flicker
+ */
+function drawTorchGlow(ctx: CanvasRenderingContext2D, x: number, y: number, baseRadius: number, intensity: number, frame: number) {
+  // Flicker radius ±2px using sine wave
+  const flicker = 2 * Math.sin(frame * 0.15 + x + y);
+  const radius = baseRadius + flicker;
+  const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
+  // Warm orange-yellow gradient stops
+  gradient.addColorStop(0, `rgba(255, 200, 100, ${0.6 * intensity})`);
+  gradient.addColorStop(0.4, `rgba(255, 160, 50, ${0.3 * intensity})`);
+  gradient.addColorStop(1, `rgba(255, 120, 0, 0)`);
+  ctx.fillStyle = gradient;
+  ctx.beginPath();
+  ctx.arc(x, y, radius, 0, Math.PI * 2);
+  ctx.fill();
+}
+
+/**
+ * Draw lighting for the room with torch glows and darker corners.
+ * Place 2 torches on walls per room.
+ * @param ctx CanvasRenderingContext2D
+ * @param x room top-left x
+ * @param y room top-left y
+ * @param w room width
+ * @param h room height
+ * @param frame current frame for animation
+ */
+function drawLighting(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, frame: number) {
+  // Darken corners with radial gradients (black to transparent)
+  const cornerRadius = Math.min(w, h) * 0.3;
+  const corners = [
+    { cx: x, cy: y },
+    { cx: x + w, cy: y },
+    { cx: x, cy: y + h },
+    { cx: x + w, cy: y + h },
+  ];
+  corners.forEach(({ cx, cy }) => {
+    const grad = ctx.createRadialGradient(cx, cy, 0, cx, cy, cornerRadius);
+    grad.addColorStop(0, 'rgba(0,0,0,0.6)');
+    grad.addColorStop(1, 'rgba(0,0,0,0)');
+    ctx.fillStyle = grad;
+    ctx.beginPath();
+    ctx.arc(cx, cy, cornerRadius, 0, Math.PI * 2);
+    ctx.fill();
+  });
+
+  // Place 2 torches on walls per room
+  // Torch positions: left wall upper quarter, right wall lower quarter
+  const torchPositions = [
+    { tx: x + w * 0.05, ty: y + h * 0.25 },
+    { tx: x + w * 0.95, ty: y + h * 0.75 },
+  ];
+  torchPositions.forEach(({ tx, ty }) => {
+    drawTorchGlow(ctx, tx, ty, 40, 1, frame);
+  });
+}
